mapper.select:
SELECT a.id, a.user_id AS userId, u.username, a.title, a.content,
img.image_url AS coverImage,
COALESCE(l.like_count, 0) AS likeCount, COALESCE(c.comment_count, 0) AS commentCount, COALESCE(f.favorite_count, 0) AS favoriteCount,
CASE WHEN ul.user_id IS NOT NULL THEN TRUE ELSE FALSE END AS liked, CASE WHEN uf.user_id IS NOT NULL THEN TRUE ELSE FALSE END AS favorited,
a.created_time AS createdTime
FROM _articles a
JOIN _user u ON u.id = a.user_id
LEFT JOIN _article_images img ON img.article_id = a.id AND img.is_cover = TRUE
LEFT JOIN ( SELECT article_id, COUNT(*) AS like_count FROM _article_likes GROUP BY article_id ) l ON l.article_id = a.id
LEFT JOIN ( SELECT article_id, COUNT(*) AS comment_count FROM _comments GROUP BY article_id ) c ON c.article_id = a.id
LEFT JOIN ( SELECT article_id, COUNT(*) AS favorite_count FROM _article_favorites GROUP BY article_id ) f ON f.article_id = a.id
LEFT JOIN _article_likes ul ON ul.article_id = a.id AND ul.user_id = #{userId}
LEFT JOIN _article_favorites uf ON uf.article_id = a.id AND uf.user_id = #{userId}
AND ( a.title LIKE CONCAT('%', #{query.keyword}, '%') OR a.content LIKE CONCAT('%', #{query.keyword}, '%') )
AND a.category_id = #{query.categoryId}
AND a.country_id = #{query.countryId}
AND a.id < #{query.lastId}
ORDER BY a.id DESC LIMIT #{query.size}

SELECT COUNT(*)
FROM _articles a


        AND (
        a.title LIKE CONCAT('%', #{keyword}, '%')
        OR a.content LIKE CONCAT('%', #{keyword}, '%')
        )


        AND a.category_id = #{categoryId}


        AND a.country_id = #{countryId}
